import os
import numpy as np
import cv2
import pickle
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score
import face_recognition
import hashlib
import secrets
from cryptography.fernet import Fernet
import base64
import json

app = Flask(__name__)

# Secure model storage
MODEL_DIR = "secure_model_storage"
os.makedirs(MODEL_DIR, exist_ok=True)

# Encryption setup
def generate_key():
    return Fernet.generate_key()

def encrypt_model(model_data, key):
    f = Fernet(key)
    return f.encrypt(model_data)

def decrypt_model(encrypted_data, key):
    f = Fernet(key)
    return f.decrypt(encrypted_data)

class SecureFaceRecognitionAPI:
    def __init__(self):
        self.model = SVC(kernel='rbf', probability=True, C=1.0, gamma='scale')
        self.label_encoder = LabelEncoder()
        self.key = generate_key()
        self.is_trained = False
        self.class_names = []
        
    def extract_face_features(self, image_path):
        image = cv2.imread(image_path)
        rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
        face_locations = face_recognition.face_locations(rgb_image)
        
        if len(face_locations) == 0:
            return None
            
        face_encodings = face_recognition.face_encodings(rgb_image, face_locations)
        return face_encodings[0] if face_encodings else None
    
    def train_model(self, employee_data_dir):
        face_features = []
        labels = []
        
        for person_name in os.listdir(employee_data_dir):
            person_dir = os.path.join(employee_data_dir, person_name)
            if not os.path.isdir(person_dir):
                continue
                
            for filename in os.listdir(person_dir):
                if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
                    image_path = os.path.join(person_dir, filename)
                    features = self.extract_face_features(image_path)
                    if features is not None:
                        face_features.append(features)
                        labels.append(person_name)
        
        if len(face_features) == 0:
            raise ValueError("No face features extracted for training")
            
        X = np.array(face_features)
        y = np.array(labels)
        
        # Encode labels
        y_encoded = self.label_encoder.fit_transform(y)
        self.class_names = self.label_encoder.classes_.tolist()
        
        # Train model
        self.model.fit(X, y_encoded)
        self.is_trained = True
        
        # Save model securely
        model_data = {
            'model': self.model,
            'label_encoder': self.label_encoder,
            'class_names': self.class_names
        }
        
        model_pickle = pickle.dumps(model_data)
        encrypted_model = encrypt_model(model_pickle, self.key)
        
        with open(os.path.join(MODEL_DIR, 'secure_model.dat'), 'wb') as f:
            f.write(encrypted_model)
            
        with open(os.path.join(MODEL_DIR, 'encryption_key.key'), 'wb') as f:
            f.write(self.key)
    
    def predict_proba(self, image_path):
        if not self.is_trained:
            raise ValueError("Model not trained yet")
            
        features = self.extract_face_features(image_path)
        if features is None:
            return None
            
        # Get probability distribution
        probabilities = self.model.predict_proba([features])[0]
        
        # Create detailed result
        result = {}
        for i, class_name in enumerate(self.class_names):
            result[class_name] = float(probabilities[i])
            
        return result
    
    def load_model(self):
        try:
            with open(os.path.join(MODEL_DIR, 'secure_model.dat'), 'rb') as f:
                encrypted_model = f.read()
                
            with open(os.path.join(MODEL_DIR, 'encryption_key.key'), 'rb') as f:
                self.key = f.read()
                
            decrypted_model = decrypt_model(encrypted_model, self.key)
            model_data = pickle.loads(decrypted_model)
            
            self.model = model_data['model']
            self.label_encoder = model_data['label_encoder']
            self.class_names = model_data['class_names']
            self.is_trained = True
            
        except Exception as e:
            print(f"Error loading model: {e}")
            self.is_trained = False

# Initialize API
face_api = SecureFaceRecognitionAPI()

# Load existing model if available
face_api.load_model()

@app.route('/train', methods=['POST'])
def train_model():
    try:
        data = request.get_json()
        employee_data_dir = data.get('employee_data_dir')
        
        if not employee_data_dir:
            return jsonify({'error': 'employee_data_dir is required'}), 400
            
        face_api.train_model(employee_data_dir)
        return jsonify({'status': 'success', 'message': 'Model trained successfully'})
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize_face():
    try:
        if not face_api.is_trained:
            return jsonify({'error': 'Model not trained'}), 400
            
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
            
        image_file = request.files['image']
        image_path = os.path.join(MODEL_DIR, 'temp_image.jpg')
        image_file.save(image_path)
        
        probabilities = face_api.predict_proba(image_path)
        os.remove(image_path)
        
        if probabilities is None:
            return jsonify({'error': 'No face detected in image'}), 400
            
        return jsonify({
            'probabilities': probabilities,
            'confidence_scores': {k: v for k, v in probabilities.items() if v > 0.01}
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/status', methods=['GET'])
def get_status():
    return jsonify({
        'model_trained': face_api.is_trained,
        'known_faces': face_api.class_names if face_api.is_trained else []
    })

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)